        'ENGINE': 'django.db.backends.sqlite3',
        'NAME': 'test_default.sqlite3',
        'TEST': {
            'NAME': 'test_default.sqlite3',
            'OPTIONS': {
                'timeout': 20,  # Increase timeout
            }
        },
    },
